import { Radio, type RadioProps } from "./radio";
import { RadioGroup as RadioGroupRoot, type RadioGroupProps } from "./radio-group";
import { RadioGroupItem, type RadioGroupItemProps } from "./radio-group-item";

const RadioGroup = Object.assign(RadioGroupRoot, {
  Item: RadioGroupItem,
});

export { Radio, type RadioProps };
export { RadioGroup, type RadioGroupProps };
export { RadioGroupItem, type RadioGroupItemProps };

"use client";

import { useMemo, useRef, type ReactNode, type Ref, type KeyboardEvent as ReactKeyboardEvent } from "react";
import { useNavigation } from "@/hooks/use-navigation";
import { useControllableState } from "@/hooks/use-controllable-state";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import type { RadioSize } from "./radio";
import type { SelectableVariant } from "@/lib/selectable-variants";
import { RadioGroupContext, type RadioGroupContextValue } from "./radio-group-context";

export interface RadioGroupProps {
  value?: string;
  defaultValue?: string;
  onChange?: (value: string) => void;
  onHighlightChange?: (value: string) => void;
  onKeyDown?: (event: ReactKeyboardEvent) => void;
  highlighted?: string | null;
  orientation?: "vertical" | "horizontal";
  wrap?: boolean;
  disabled?: boolean;
  size?: RadioSize;
  variant?: SelectableVariant;
  name?: string;
  required?: boolean;
  label?: string;
  labelledBy?: string;
  className?: string;
  children: ReactNode;
  ref?: Ref<HTMLDivElement>;
}

export function RadioGroup({
  value: controlledValue,
  defaultValue,
  onChange,
  onHighlightChange,
  onKeyDown,
  highlighted: controlledHighlighted,
  orientation = "vertical",
  wrap = true,
  disabled = false,
  size = "md",
  variant = "bullet",
  name,
  required,
  label,
  labelledBy,
  className,
  children,
  ref,
}: RadioGroupProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  const [value, setValue] = useControllableState<string | undefined>({
    value: controlledValue,
    defaultValue,
    onChange: onChange as ((value: string | undefined) => void) | undefined,
  });
  const [highlightedValue, setHighlightedValue] = useControllableState<string | null>({
    value: controlledHighlighted,
    defaultValue: null,
    onChange: onHighlightChange as ((value: string | null) => void) | undefined,
  });

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "radio",
    orientation,
    wrap,
    moveFocus: true,
    upKeys: ["ArrowUp", "ArrowLeft"],
    downKeys: ["ArrowDown", "ArrowRight"],
    value: highlightedValue ?? undefined,
    onValueChange: (next) => {
      setHighlightedValue(next);
      setValue(next);
    },
  });

  const handleKeyDown = (e: ReactKeyboardEvent) => {
    onKeyDown?.(e);
    if (!e.defaultPrevented) navKeyDown(e);
  };

  const contextValue: RadioGroupContextValue = useMemo(() => ({
    value,
    onChange: setValue,
    onHighlightChange: setHighlightedValue,
    disabled,
    size,
    variant,
    highlightedValue,
    name,
    required,
    containerRef,
  }), [value, setValue, setHighlightedValue, disabled, size, variant, highlightedValue, name, required]);

  return (
    <RadioGroupContext value={contextValue}>
      <div
        ref={composeRefs(containerRef, ref)}
        role="radiogroup"
        aria-label={label}
        aria-labelledby={labelledBy}
        aria-orientation={orientation}
        aria-required={required || undefined}
        aria-disabled={disabled || undefined}
        className={cn(
          "flex",
          orientation === "vertical" ? "flex-col gap-2" : "flex-row gap-4",
          className
        )}
        onKeyDown={handleKeyDown}
      >
        {children}
      </div>
    </RadioGroupContext>
  );
}

"use client";

import { useId, type KeyboardEvent as ReactKeyboardEvent, type ReactNode, type Ref } from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import {
  selectableVariants,
  selectableContainerClass,
  selectableIndicatorVariants,
  selectableLabelVariants,
  selectableDescriptionVariants,
  selectableIndicators,
  type SelectableSize,
  type SelectableVariant,
} from "@/lib/selectable-variants";
import { cn } from "@/lib/utils";

export type RadioSize = SelectableSize;

export interface RadioProps {
  checked?: boolean;
  defaultChecked?: boolean;
  isTabTarget?: boolean;
  onChange?: (checked: boolean) => void;
  onMouseEnter?: () => void;
  label?: ReactNode;
  description?: ReactNode;
  disabled?: boolean;
  highlighted?: boolean;
  size?: RadioSize;
  name?: string;
  required?: boolean;
  invalid?: boolean;
  variant?: SelectableVariant;
  "aria-label"?: string;
  "aria-invalid"?: boolean;
  className?: string;
  ref?: Ref<HTMLDivElement>;
  "data-value"?: string;
}

export function Radio({
  checked,
  defaultChecked = false,
  isTabTarget = true,
  onChange,
  onMouseEnter,
  label,
  description,
  disabled = false,
  highlighted = false,
  size = "md",
  variant = "bullet",
  name,
  required,
  invalid,
  "aria-label": ariaLabel,
  "aria-invalid": ariaInvalid,
  className,
  ref,
  "data-value": dataValue,
}: RadioProps) {
  const generatedId = useId();
  const labelId = `${generatedId}-label`;
  const descriptionId = `${generatedId}-desc`;

  const [isChecked, setIsChecked] = useControllableState<boolean>({
    value: checked,
    defaultValue: defaultChecked,
    onChange,
  });

  const toggle = () => {
    if (disabled) return;
    setIsChecked(true);
  };

  const handleKeyDown = (e: ReactKeyboardEvent) => {
    if (disabled) return;
    if (e.key === " ") {
      e.preventDefault();
      toggle();
    }
  };

  return (
    <div
      ref={ref}
      role="radio"
      data-value={dataValue}
      aria-checked={isChecked}
      aria-disabled={disabled || undefined}
      aria-invalid={invalid || ariaInvalid || undefined}
      aria-label={ariaLabel}
      aria-labelledby={!ariaLabel && label ? labelId : undefined}
      aria-describedby={description ? descriptionId : undefined}
      tabIndex={!disabled && isTabTarget ? 0 : -1}
      onClick={toggle}
      onKeyDown={handleKeyDown}
      onMouseEnter={onMouseEnter}
      className={cn(
        selectableVariants({ highlighted, disabled }),
        selectableContainerClass,
        description && "items-start",
        className
      )}
    >
      <input
        type="radio"
        name={name}
        value={dataValue ?? ""}
        checked={isChecked}
        required={required}
        disabled={disabled}
        className="sr-only"
        tabIndex={-1}
        readOnly
        aria-hidden="true"
      />
      <span
        aria-hidden="true"
        className={selectableIndicatorVariants({
          size,
          checked: isChecked,
          highlighted,
        })}
      >
        {selectableIndicators[variant][isChecked ? "checked" : "unchecked"]}
      </span>
      {label && (
        <div
          className={cn(
            "flex flex-col min-w-0",
            !description && "justify-center"
          )}
        >
          <span id={labelId} className={selectableLabelVariants({ size })}>{label}</span>
          {description && (
            <span id={descriptionId} className={selectableDescriptionVariants({ highlighted })}>
              {description}
            </span>
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import type { ReactNode } from "react";
import { useRadioGroupContext } from "./radio-group-context";
import { Radio } from "./radio";
import { resolveTabTarget } from "@/lib/resolve-tab-target";

export interface RadioGroupItemProps {
  value: string;
  label: ReactNode;
  description?: ReactNode;
  disabled?: boolean;
  className?: string;
}

export function RadioGroupItem({
  value,
  label,
  description,
  disabled: itemDisabled,
  className,
}: RadioGroupItemProps) {
  const context = useRadioGroupContext();
  const isSelected = context.value === value;
  const isDisabled = context.disabled || !!itemDisabled;
  const isHighlighted = context.highlightedValue === value;
  const hasSelection = context.value !== undefined;
  const isTabTarget = resolveTabTarget(isSelected, hasSelection, context.containerRef.current, value);

  return (
    <Radio
      data-value={value}
      checked={isSelected}
      isTabTarget={isTabTarget}
      onChange={() => context.onChange(value)}
      onMouseEnter={isDisabled ? undefined : () => context.onHighlightChange(value)}
      label={label}
      description={description}
      disabled={isDisabled}
      highlighted={isHighlighted}
      size={context.size}
      variant={context.variant}
      name={context.name}
      required={context.required}
      className={className}
    />
  );
}

"use client";

import { createContext, useContext, type RefObject } from "react";
import type { RadioSize } from "./radio";
import type { SelectableVariant } from "@/lib/selectable-variants";

export interface RadioGroupContextValue {
  value?: string;
  onChange: (value: string) => void;
  onHighlightChange: (value: string) => void;
  disabled: boolean;
  size: RadioSize;
  variant: SelectableVariant;
  highlightedValue: string | null;
  name?: string;
  required?: boolean;
  containerRef: RefObject<HTMLDivElement | null>;
}

export const RadioGroupContext = createContext<RadioGroupContextValue | undefined>(undefined);

export function useRadioGroupContext() {
  const context = useContext(RadioGroupContext);
  if (!context) {
    throw new Error("RadioGroupItem must be used within RadioGroup");
  }
  return context;
}
